sql_query:
SELECT "Primary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Esophageal/GEJ' AND "Trial phase" = 'Phase 3';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Primary endpoint" AS source_value FROM clinical_trials
WHERE "Cancer type" = 'Esophageal/GEJ' AND "Trial phase" = 'Phase 3'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_primary_endpoint_category(source_value) AS "primary_endpoint_category"
FROM base;
